          }
        }}
        open={addFilterOpen}
      >
        <PopoverTrigger
          className="sr-only"
          ref={triggerRef}
          tabIndex={-1}
        />
        <PopoverContent
          align="start"
          className="w-fit origin-(--radix-popover-content-transform-origin) p-0"
          onOpenAutoFocus={(e) => {
            e.preventDefault();
            inputRef.current?.focus();
          }}
          side="bottom"
        >
          {popoverContent}
        </PopoverContent>
      </Popover>
    </div>
  );
}

function FilterableColumnItem<TData>({
  column,
  onSelect,
}: {
